Code:
public int[] fix45(int[] nums) {
    int n = nums.length;
    int j = 0;

    for (int i = 0; i < n; i++) {
        if(nums[i] == 4 && nums[i+1] != 5) {
            while(j < n) {
                if(nums[j] == 5) {
                    int temp = nums[i+1];
                    nums[i+1] = nums[j];
                    nums[j] = temp;
                    break;
                }
                j++;
            }
        }
    }

    return nums;
}

